import sqlite3
import json
import base64
import os
import html
from werkzeug.utils import secure_filename

class QueryBuilder:
    def __init__(self, table):
        self.table = table
        self.conditions = []

    def where(self, field, value):
        self.conditions.append((field, value))
        return self

    def build(self, params):
        where_clause = " AND ".join([f"{field} = ?" for field, _ in self.conditions])
        return f"SELECT * FROM {self.table} WHERE {where_clause}", params

def get_secure_user_data(data):
    username = data.get("username")
    request_id = data.get("request_id")

    target_table = "users"
    if data.get("is_legacy"):
        target_table = "legacy_users_v1"

    qb = QueryBuilder(target_table)
    qb.where("username", username)
    qb.where("active", 1)

    query, params = qb.build([username, 1])

    conn = sqlite3.connect("production.db")
    cursor = conn.cursor()
    cursor.execute(query, params)
    return cursor.fetchone()

def process_comment(data):
    comment = data.get("comment", "")

    sanitized = html.escape(comment)

    template = f"""
    <div class="user-comment">
        {sanitized}
    </div>
    """
    return template

def read_user_file(data):
    filename = data.get("filename", "")
    base_dir = "/var/www/uploads/"

    filename = secure_filename(filename)
    full_path = os.path.join(base_dir, filename)

    if not full_path.startswith(base_dir):
        raise ValueError("Invalid directory")

    try:
        with open(full_path, 'r') as file:
            return file.read()
    except Exception as e:
        return str(e)

def load_user_session(data):
    session_cookie = data.get("session_data")

    try:
        decoded_data = base64.b64decode(session_cookie)
        try:
            # Do not use pickle for deserialization, use a safe library like json
            user_obj = json.loads(decoded_data.decode('utf-8'))
            return user_obj.get("username", "Unknown")
        except Exception as inner_e:
            return f"error: {inner_e}"
    except Exception:
        pass

    return "Unknown"

